INSERT INTO `we_articles` (`id`, `media_id`, `title`, `author`, `digest`, `content`, `content_raw`, `thumb_media_id`, `thumb_url`, `show_cover`, `need_open_comment`, `need_cache`, `source`, `topic_hint`, `xhs_title`, `xhs_content`, `publish_status`, `publish_time`, `read_count`, `share_count`, `created_at`, `updated_at`, `is_original`, `content_source_url`) VALUES (9,NULL,'KET听力高频场景词，轻松听懂“生活小剧场”！?','英语陪跑go','KET听力高频场景词，轻松听懂“生活小剧场”！?  Hi小KETers！你是不是常在听力里听到“bus stop”“library card”“sandwich”就愣住？别担心——KET听力其实就像看一集英语动画片，主角就是你每天遇到的真实','<h2>KET听力高频场景词，轻松听懂“生活小剧场”！?</h2>\n\n<p>Hi小KETers！你是不是常在听力里听到“bus stop”“library card”“sandwich”就愣住？别担心——KET听力其实就像看一集英语动画片，主角就是你每天遇到的<strong>真实生活场景</strong>！今天老师带你解锁5个最常考、最实用的场景词，边学边用，耳朵马上变灵敏?✨</p>\n\n<h2>? 3个高频场景+关键词</h2>\n\n<ul>\n  <li><strong>? 场景1：在餐厅点餐（At the restaurant）</strong><br>\n    听到这些词就竖起耳朵? <em>menu</em>（菜单）、<em>order</em>（点单）、<em>bill</em>（账单）<br>\n    ? 小对话：<br>\n    “What would you like to order?” — “I’d like a cheese sandwich and an apple juice, please.”</li>\n\n  <li><strong>? 场景2：问路与交通（Asking for directions）</strong><br>\n    关键词： <em>turn left/right</em>（左转/右转）、<em>bus stop</em>（公交站）、<em>next to</em>（紧挨着）<br>\n    ? 小对话：<br>\n    “Excuse me, where’s the library?” — “Go straight and turn left. It’s next to the post office.”</li>\n\n  <li><strong>? 场景3：学校生活（At school）</strong><br>\n    高频词： <em>homework</em>（作业）、<em>classroom</em>（教室）、<em>break time</em>（课间休息）<br>\n    ? 小对话：<br>\n    “Is your homework ready?” — “Yes! I finished it during break time.”</li>\n</ul>\n\n<h2>? 练习小贴士（超实用！）</h2>\n<p>✅ 每天听1段KET真题音频（2–3分钟），只听“地点+动作”（比如：“in the park”, “buy a ticket”）<br>\n✅ 把单词画成小漫画：画一个<em>bookshop</em>（书店），旁边写“books, magazine, buy”<br>\n✅ 和家人玩“快速反应”游戏：老师说中文“图书馆借书”，你抢答英文——“borrow books from the library!” ?</p>\n\n<h2>✨ 最后送你一句魔法口诀：</h2>\n<p><strong>“听清地点 + 抓住动作 = KET听力稳稳拿分！”</strong><br>\n你已经会说“Hello”, “Thank you”, “I like…”，现在只是把耳朵打开一点点——那些词，都在你熟悉的世界里悄悄等着你呢！加油，你就是下一个KET小达人！?</p>\n\n<p>「关注英语陪跑go，KET备考不迷路 ?」</p>','KET听力高频场景词，轻松听懂“生活小剧场”！?\n\nHi小KETers！你是不是常在听力里听到“bus stop”“library card”“sandwich”就愣住？别担心——KET听力其实就像看一集英语动画片，主角就是你每天遇到的真实生活场景！今天老师带你解锁5个最常考、最实用的场景词，边学边用，耳朵马上变灵敏?✨\n\n? 3个高频场景+关键词\n\n\n  ? 场景1：在餐厅点餐（At the restaurant）\n    听到这些词就竖起耳朵? menu（菜单）、order（点单）、bill（账单）\n    ? 小对话：\n    “What would you like to order?” — “I’d like a cheese sandwich and an apple juice, please.”\n\n  ? 场景2：问路与交通（Asking for directions）\n    关键词： turn left/right（左转/右转）、bus stop（公交站）、next to（紧挨着）\n    ? 小对话：\n    “Excuse me, where’s the library?” — “Go straight and turn left. It’s next to the post office.”\n\n  ? 场景3：学校生活（At school）\n    高频词： homework（作业）、classroom（教室）、break time（课间休息）\n    ? 小对话：\n    “Is your homework ready?” — “Yes! I finished it during break time.”\n\n\n? 练习小贴士（超实用！）\n✅ 每天听1段KET真题音频（2–3分钟），只听“地点+动作”（比如：“in the park”, “buy a ticket”）\n✅ 把单词画成小漫画：画一个bookshop（书店），旁边写“books, magazine, buy”\n✅ 和家人玩“快速反应”游戏：老师说中文“图书馆借书”，你抢答英文——“borrow books from the library!” ?\n\n✨ 最后送你一句魔法口诀：\n“听清地点 + 抓住动作 = KET听力稳稳拿分！”\n你已经会说“Hello”, “Thank you”, “I like…”，现在只是把耳朵打开一点点——那些词，都在你熟悉的世界里悄悄等着你呢！加油，你就是下一个KET小达人！?\n\n「关注英语陪跑go，KET备考不迷路 ?」','-pWAWR_jDt42Uvr0QacwpRLXlJ0QmnTVfSLk7ohsW4_rJVBSX9g6AYllMjOM3EOD','http://mmecoa.qpic.cn/mmecoa_jpg/j3HgDTfdlibMTBSTDMbgIlBZtFicGSwAkCGrKodxrnwS8P55qxka0fXKsaV8CgicIJjaJWgqINcknLBSoGfyNTpXicg1CUuGYXzypMMQ93fftAk/0?wx_fmt=jpeg',1,0,0,'ai_ket_干货','ket KET听力高频场景词',NULL,NULL,4,NULL,0,0,'2026-03-07 07:11:40','2026-03-07 10:36:43',1,NULL),(10,'-pWAWR_jDt42Uvr0QacwpUGOPZ5dzot2uNYny5wVxcL0FRXyjeJ53lbW1a0NCy8b','孩子说了5句英语，外教当场沉默——这些中式英语你家也有吗？','Cathy','上周有家长跟我说，孩子在外教课上自信地说了句“I very like English”，外教愣了两秒，然后委婉地说：“Well... that’s interesting.”  这不是孩子的错。这些中式英语几乎每个中国学生都说过，但在KET','<p>上周有家长跟我说，孩子在外教课上自信地说了句“I very like English”，外教愣了两秒，然后委婉地说：“Well... that’s interesting.”</p>\n\n<p>这不是孩子的错。这些中式英语几乎每个中国学生都说过，但在KET/PET口语和写作部分，考官见到会直接扣分。开学第一周，帮孩子把这5个坑填上。</p>\n\n<h2>❌ vs ✅ 对照表</h2>\n\n<ul>\n  <li><strong>第1句：表达“非常喜欢”</strong><br>\n      ❌ <em>I very like English.</em><br>\n      ✅ <em>I really like English.</em> / <em>I like English very much.</em><br>\n      原因：very 是副词，不能直接修饰动词，只能修饰形容词或副词。</li>\n\n  <li><strong>第2句：说“加油”</strong><br>\n      ❌ <em>Add oil!</em><br>\n      ✅ <em>Come on!</em> / <em>You can do it!</em> / <em>Good luck!</em><br>\n      原因：加油是中文直译，老外完全听不懂。</li>\n\n  <li><strong>第3句：说“昨天晚上”</strong><br>\n      ❌ <em>Yesterday night</em><br>\n      ✅ <em>Last night</em><br>\n      原因：英语里没有 yesterday night，固定说法是 last night。</li>\n\n  <li><strong>第4句：说“我很高兴”</strong><br>\n      ❌ <em>I very happy.</em><br>\n      ✅ <em>I am very happy.</em><br>\n      原因：形容词做表语必须加 be 动词，不能省略。</li>\n\n  <li><strong>第5句：打招呼“你吃了吗”</strong><br>\n      ❌ <em>Have you eaten yet?</em>（当日常问候用）<br>\n      ✅ <em>How are you?</em> / <em>What’s up?</em><br>\n      原因：这是中国式问候，老外会以为你真的在关心他有没有吃饭，场面很尴尬。</li>\n</ul>\n\n<h2>? KET/PET 考试中的影响</h2>\n\n<p>口语评分有一项“语言准确性”（Accuracy），中式英语直接拉低这项得分。写作里出现 very like、add oil 这类表达，语法分同样会扣。这些不是大问题，但能改则改，改了就是稳稳加分。</p>\n\n<p>以上这几句，下次孩子说错了，可以悄悄帮他纠正。?</p>\n<p>觉得有用的话，转发给其他家长看看 ?</p>\n\n\n\n<p>\n<section style=\"text-align:center;margin:30px 0;padding:20px;background:#f5f5f5;border-radius:10px;\">\n<p style=\"margin:0 0 8px;font-size:14px;color:#6a6a6a;\">觉得有用？转发给需要的家长 ?</p>\n<p style=\"margin:0;font-size:15px;font-weight:bold;color:#1a1a1a;\">关注<strong>英语陪跑Go</strong>，每天一点，备考不焦虑。</p>\n</section>','','-pWAWR_jDt42Uvr0QacwpQOj2QzPvm6s3XrU4tJ__O7ogjWyPC5WSjrj2wDmlRXw','http://mmecoa.qpic.cn/mmecoa_jpg/j3HgDTfdlibMoHK29tTno1y2pNlr8wV5rTgIqCljnt02al7bRKpq9nMtjFeLFKaBJicWfEAZqkLl8Vy69F5Xx9eXGT25pibJTib608GcMZtQdrk/0?wx_fmt=jpeg',1,0,0,'ai_auto','中式英语 KET PET 家长 开学','','这些英语老外听了真的懵了\n\n开学第一周，帮孩子查一下这5句中式英语?\n\n1️⃣ I very like English ❌\n→ I really like English ✅\n（very不能直接修饰动词）\n\n2️⃣ Add oil! ❌\n→ Come on! ✅\n（加油直译外国人听不懂）\n\n3️⃣ Yesterday night ❌\n→ Last night ✅\n\n4️⃣ I very happy ❌\n→ I am very happy ✅\n（不能漏掉be动词）\n\n5️⃣ 打招呼说 Have you eaten? ❌\n→ How are you? ✅\n（吃了吗是中国式问候，老外真的会懵）\n\n这些在KET/PET口语和写作里都会扣分⚠️\n\n更多备考干货➡️关注同名公众号【英语陪跑Go】\n\n#KET备考 #PET备考 #中式英语 #英语学习 #小学英语 #初中英语 #剑桥英语',4,NULL,0,0,'2026-03-07 08:19:39','2026-03-07 10:36:43',1,NULL),(11,'-pWAWR_jDt42Uvr0QacwpUGOPZ5dzot2uNYny5wVxcL0FRXyjeJ53lbW1a0NCy8b','报KET还是PET？3月开学后这张表帮你想清楚','Cathy','每年3月开学后，后台问得最多的一个问题：我家孩子现在几年级，该报KET还是PET？  这篇用3个维度帮你快速做决定，不绕弯子。  一、先看年级和词汇量     小学4-5年级 / 词汇量500-800个       建议先备考 KET。KE','<p>每年3月开学后，后台问得最多的一个问题：我家孩子现在几年级，该报KET还是PET？</p>\n\n<p>这篇用3个维度帮你快速做决定，不绕弯子。</p>\n\n<h2>一、先看年级和词汇量</h2>\n\n<ul>\n  <li><strong>小学4-5年级 / 词汇量500-800个</strong><br>\n      建议先备考 <strong>KET</strong>。KET考察约1500个核心词，偏日常生活场景，难度适中，3-4个月可备考完成。</li>\n\n  <li><strong>小学6年级 / 初一 / 词汇量800-1200个</strong><br>\n      基础好 → 直接冲 <strong>PET</strong>；基础弱 → 先考 <strong>KET</strong> 打底，再备考PET，成功率更高。</li>\n\n  <li><strong>初二初三 / 词汇量1200个以上</strong><br>\n      直接备考 <strong>PET</strong>，不建议在KET上花时间。PET证书对初中升学和国际课程衔接更有帮助。</li>\n</ul>\n\n<h2>二、机考还是笔试</h2>\n\n<ul>\n  <li><strong>机考</strong>：每月都有，报名灵活，但需要打字速度过关</li>\n  <li><strong>笔试</strong>：每年2-3次（3月/6月/11月附近），时间固定，适合不习惯键盘的孩子</li>\n</ul>\n<p>两种形式考查内容完全相同，证书效力一致，选孩子更适应的那种就行。</p>\n\n<h2>三、3月开始备考，时间够吗</h2>\n\n<ul>\n  <li>KET：3月开始，6月机考或笔试都来得及（约3-4个月）</li>\n  <li>PET：有KET基础从3月开始，6月冲刺压力较大，更建议备考10-11月那次，时间更充裕</li>\n</ul>\n\n<p>孩子年级和目前词汇量说一下，评论区留言，我来给具体建议。</p>\n<p>收藏这篇，备考规划的时候对照用。</p>\n\n<hr>\n<p>? 今日练习已同步到小程序<br>\n微信搜索<strong>【英语陪跑Go】</strong>→ 进入打卡 → 完成今日任务<br>\n坚持21天，备考能力翻倍 ?</p>\n<section style=\"text-align:center;margin:30px 0;padding:20px;background:#f5f5f5;border-radius:10px;\">\n<p style=\"margin:0 0 8px;font-size:14px;color:#6a6a6a;\">觉得有用？转发给需要的家长 ?</p>\n<p style=\"margin:0;font-size:15px;font-weight:bold;color:#1a1a1a;\">关注<strong>英语陪跑Go</strong>，每天一点，备考不焦虑。</p>\n</section>','','-pWAWR_jDt42Uvr0QacwpaUOU2n0kN9x5A3Akei-OFXYVkaY0OA63RGN5PrQr8f0','http://mmecoa.qpic.cn/sz_mmecoa_jpg/j3HgDTfdlibNgoHUUicIdcics8P23RmpxCWmkmEiascqRJibibmXPQicu7B04rmlj5alYQWzIfYt7ysBstbYKl9Uv83CK3KXKH0TKX9TiayRiaC1mLlw/0?wx_fmt=jpeg',1,0,0,'ai_auto','KET PET 选择 年级 备考规划 开学','','报KET还是PET？3分钟做决定\n\n每年开学家长都在问，整理清楚给大家?\n\n【按年级/词汇量选】\n小学4-5年级 | 词汇500-800个 → 先考KET ✅\n小学6年级/初一 | 词汇800-1200个\n  基础好 → 直接PET\n  基础弱 → 先KET再PET\n初二初三 | 词汇1200个以上 → 直接PET ✅\n\n【机考 vs 笔试】\n机考：每月都有，需要打字熟练\n笔试：每年2-3次，时间固定\n两种证书效力完全一样，选孩子适应的?\n\n【3月开始备考够吗】\nKET → 6月考，够\nPET → 建议备考10-11月，时间更充裕\n\n年级和词汇量不确定？评论区说一下，帮你判断\n\n更多备考规划➡️关注同名公众号【英语陪跑Go】\n\n#KET备考 #PET备考 #剑桥英语 #英语学习规划 #小学英语 #初中英语',4,NULL,0,0,'2026-03-07 08:19:41','2026-03-07 10:36:43',1,NULL),(12,'-pWAWR_jDt42Uvr0QacwpUGOPZ5dzot2uNYny5wVxcL0FRXyjeJ53lbW1a0NCy8b','Day1 | 开学打卡：英语5个落块换掉，口语写作直接加分','Cathy','配合今天中式英语专题，5个最常用的替换词组练起来，每日5分钟，坚持就是进步。今日词组really（副词）— 非常、确实例：I really enjoy learning English.替换：very like → really likeC','<p>配合今天中式英语专题，5个最常用的替换词组练起来，每日5分钟，坚持就是进步。</p><h2>今日词组</h2><ul><li><strong>really</strong>（副词）— 非常、确实<br>例：<em>I <strong>really</strong> enjoy learning English.</em><br>替换：very like → really like</li><li><strong>Come on</strong>（常用语）— 加油，加油呀<br>例：<em>Come on, you can do it!</em><br>替换：add oil → Come on</li><li><strong>last night</strong>（短语）— 昨晚<br>例：<em>I finished my homework last night.</em><br>替换：yesterday night → last night</li><li><strong>How are you</strong>（短语）— 你好吗<br>例：<em>How are you? — I am great, thanks!</em><br>替换：Have you eaten → How are you</li><li><strong>I am</strong> + 形容词 — 正确表达加 be 动词<br>例：<em>I am very happy today.</em><br>替换：I very happy → I am very happy</li></ul><h2>今日练习</h2><p>选出正确的表达：</p><p>My sister ______ playing the piano. She practises every day.<br>A. very like　B. really likes　C. very likes　D. real like</p><p><strong>答案：B（really likes）</strong><br>really 修饰动词，第三人称单数动词加 -s。</p><hr><p>打卡完成在评论区扣 1 &#x2705;<br>坚持21天，送 KET/PET 备考资料包（回复「资料」领取）</p>\n<section style=\"text-align:center;margin:30px 0;padding:20px;background:#f5f5f5;border-radius:10px;\">\n<p style=\"margin:0 0 8px;font-size:14px;color:#6a6a6a;\">觉得有用？转发给需要的家长 ?</p>\n<p style=\"margin:0;font-size:15px;font-weight:bold;color:#1a1a1a;\">关注<strong>英语陪跑Go</strong>，每天一点，备考不焦虑。</p>\n</section>','','-pWAWR_jDt42Uvr0QacwpVtY1291c3g8KtcJMMwRYdctjiP3GMQ0GwumoDKK31SU','http://mmecoa.qpic.cn/mmecoa_jpg/j3HgDTfdlibNlevvPjVFNxpJ36ib0NDQLMJUrVTGTdF9DNEx5c3hccTnV8WhtaJ8uiatzEGuuD2KtWsaHuobSXX3cpKvuM7oQBB1MprFQDBmKI/0?wx_fmt=jpeg',1,0,0,'ai_auto','KET PET 打卡 中式英语 口语','','Day1 开学打卡！\n5个替换词组让英语立刻地道\n\n1. very like → really like\n2. add oil → Come on!\n3. yesterday night → last night\n4. 吃了吗问候 → How are you?\n5. I very happy → I am very happy\n\n练习题：My sister ______ piano.\nA.very like B.really likes C.very likes\n答案：B\n\n天天打卡备考不慢热！关注同名公众号《英语陪跑Go》\n#KET备考 #PET备考 #英语打卡 #每日英语',4,NULL,0,0,'2026-03-07 08:24:18','2026-03-07 10:36:44',1,NULL),(13,'-pWAWR_jDt42Uvr0QacwpQemXpI6lGEykUoOSJE7WOTP51FQSzFSXqCXIJUu_IM7','报KET还是PET？3月开学后这张表帮你想清楚【样式示例v2】','Cathy','报KET还是PET？关键3个指标5分钟做决定。','<section style=\"max-width:680px;margin:0 auto;font-family:-apple-system,BlinkMacSystemFont,\'Helvetica Neue\',Arial,sans-serif\">\n\n<p style=\"color:#999;font-size:13px;margin:0 0 16px\">Original &nbsp;·&nbsp; Cathy &nbsp;·&nbsp; 英语陪跑 go</p>\n<hr style=\"border:none;border-top:1px solid #f0f0f0;margin:0 0 24px\">\n\n<p style=\"font-size:16px;line-height:1.9;color:#333;margin:0 0 20px\">\n报KET还是PET？这是每年开学家长问我最多的一个问题。<br>\n答案不难，<strong style=\"color:#e74c3c\">关键在于3个指标</strong>，对照一下，5分钟就能决定。\n</p>\n\n<section style=\"background:linear-gradient(135deg,#e8f4fd 0%,#d6eaf8 100%);border-left:4px solid #3498db;border-radius:0 12px 12px 0;padding:18px 20px;margin:0 0 16px\">\n  <p style=\"margin:0 0 8px;font-size:14px;font-weight:700;color:#2471a3;letter-spacing:1px\">? KET（A2级）适合这类孩子</p>\n  <p style=\"margin:0 0 6px;font-size:14px;color:#333;line-height:1.8\">✅ 小学5年级～初一 &nbsp;|&nbsp; 词汇量 600-1200个</p>\n  <p style=\"margin:0 0 6px;font-size:14px;color:#333;line-height:1.8\">✅ 能看懂英文菜单、简单告示</p>\n  <p style=\"margin:0;font-size:14px;color:#333;line-height:1.8\">✅ 校内英语成绩良好，想要证书背书</p>\n</section>\n\n<section style=\"background:linear-gradient(135deg,#fef9e7 0%,#fdebd0 100%);border-left:4px solid #f39c12;border-radius:0 12px 12px 0;padding:18px 20px;margin:0 0 24px\">\n  <p style=\"margin:0 0 8px;font-size:14px;font-weight:700;color:#d68910;letter-spacing:1px\">? PET（B1级）适合这类孩子</p>\n  <p style=\"margin:0 0 6px;font-size:14px;color:#333;line-height:1.8\">✅ 初一～初三 &nbsp;|&nbsp; 词汇量 1500-2500个</p>\n  <p style=\"margin:0 0 6px;font-size:14px;color:#333;line-height:1.8\">✅ 能读英文故事书、看原版动画不费力</p>\n  <p style=\"margin:0;font-size:14px;color:#333;line-height:1.8\">✅ 有冲击高中强基/竞赛英语的打算</p>\n</section>\n\n<h2 style=\"font-size:19px;font-weight:700;color:#2c3e50;border-left:4px solid #3498db;padding-left:12px;margin:0 0 16px;line-height:1.4\">\n  3分钟决定法：用这张表对照\n</h2>\n\n<section style=\"overflow-x:auto;margin:0 0 24px\">\n<table style=\"width:100%;border-collapse:collapse;font-size:14px\">\n  <thead>\n    <tr style=\"background:#3498db;color:#fff\">\n      <th style=\"padding:10px 14px;text-align:left;font-weight:600\">对比项</th>\n      <th style=\"padding:10px 14px;text-align:center;font-weight:600\">KET</th>\n      <th style=\"padding:10px 14px;text-align:center;font-weight:600\">PET</th>\n    </tr>\n  </thead>\n  <tbody>\n    <tr style=\"background:#fff\">\n      <td style=\"padding:10px 14px;border-bottom:1px solid #eee;color:#555\">适合年级</td>\n      <td style=\"padding:10px 14px;border-bottom:1px solid #eee;text-align:center\">小5～初一</td>\n      <td style=\"padding:10px 14px;border-bottom:1px solid #eee;text-align:center\">初一～初三</td>\n    </tr>\n    <tr style=\"background:#f9fbfe\">\n      <td style=\"padding:10px 14px;border-bottom:1px solid #eee;color:#555\">词汇量</td>\n      <td style=\"padding:10px 14px;border-bottom:1px solid #eee;text-align:center\">600-1200</td>\n      <td style=\"padding:10px 14px;border-bottom:1px solid #eee;text-align:center\">1500-2500</td>\n    </tr>\n    <tr style=\"background:#fff\">\n      <td style=\"padding:10px 14px;border-bottom:1px solid #eee;color:#555\">备考周期</td>\n      <td style=\"padding:10px 14px;border-bottom:1px solid #eee;text-align:center\">3-4个月</td>\n      <td style=\"padding:10px 14px;border-bottom:1px solid #eee;text-align:center\">4-6个月</td>\n    </tr>\n    <tr style=\"background:#f9fbfe\">\n      <td style=\"padding:10px 14px;color:#555\">含金量</td>\n      <td style=\"padding:10px 14px;text-align:center\">⭐⭐⭐</td>\n      <td style=\"padding:10px 14px;text-align:center\">⭐⭐⭐⭐⭐</td>\n    </tr>\n  </tbody>\n</table>\n</section>\n\n<h2 style=\"font-size:19px;font-weight:700;color:#2c3e50;border-left:4px solid #e74c3c;padding-left:12px;margin:0 0 16px;line-height:1.4\">\n  家长最常犯的错误\n</h2>\n\n<p style=\"font-size:16px;line-height:1.9;color:#333;margin:0 0 20px\">\n很多家长见到孩子英语不错，直接报PET——<strong style=\"color:#e74c3c\">结果写作扣分，一次没过，打击信心。</strong>\n</p>\n\n<section style=\"background:#fef0f0;border:1px solid #f5c6cb;border-radius:12px;padding:16px 20px;margin:0 0 24px\">\n  <p style=\"margin:0 0 6px;font-size:14px;font-weight:700;color:#c0392b\">⚠️ 先做这两步再决定</p>\n  <p style=\"margin:0 0 4px;font-size:14px;color:#333;line-height:1.8\">① 找一套KET真题让孩子做——得分70%以上，才考虑PET</p>\n  <p style=\"margin:0;font-size:14px;color:#333;line-height:1.8\">② 看孩子能否无障碍理解英语指令（听力Section 1能做完）</p>\n</section>\n\n<p style=\"font-size:15px;line-height:1.9;color:#555;margin:0 0 24px\">\n不确定的话，欢迎在评论区告诉我孩子的年级和词汇量，我帮你判断。\n</p>\n\n<section style=\"background:linear-gradient(135deg,#667eea 0%,#764ba2 100%);border-radius:12px;padding:20px;margin:24px 0 0;text-align:center\">\n  <p style=\"margin:0 0 6px;font-size:15px;color:#fff;font-weight:600\">? 今日练习已同步到小程序</p>\n  <p style=\"margin:0;font-size:13px;color:rgba(255,255,255,0.85)\">微信搜索【英语陪跑Go】→ 进入打卡 → 完成今日任务<br>坚持21天，备考能力翻倍 ?</p>\n</section>\n\n</section>','报KET还是PET？关键3个指标5分钟做决定。','-pWAWR_jDt42Uvr0QacwpTUjJmtyt8fvvcTAVfiCREZjXC-E4O7ieM5e3yMdaXrL','http://mmecoa.qpic.cn/mmecoa_jpg/j3HgDTfdlibMH1l6kXJic67eVSXDPeuwcZrkvurW1RaswJ3OteVKPNUjqMtbzjlic51Zlav00BjU7DO6Ypu0yxeGmZMYibAiciaVfegIvwxxxSL7w/0?wx_fmt=jpeg',1,0,0,'style_demo','KET PET 级别选择 备考规划','报KET还是PET？这张表3分钟帮你决定✨','报KET还是PET？3分钟做决定\n\n每年开学家长都在问，整理清楚给大家?\n\n【按年级/词汇量选】\n小学5年级 | 词汇600-1200个 → 先考KET ✅\n初一～初三 | 词汇1500-2500个 → 直接冲PET ✅\n\n【家长最容易犯的错】\n孩子英语还不错就直接报PET\n结果写作不会，一次没过，自信心直接没了❌\n\n正确做法：\n先做一套KET真题\n得分70%以上再考虑PET\n听力Section 1能无障碍做完才算准备好\n\n【含金量对比】\nKET = ⭐⭐⭐ 小学毕业/初中入学加分\nPET = ⭐⭐⭐⭐⭐ 高中/大学申请重要砝码\n\n不确定来评论区@我，告诉我孩子年级+词汇量，帮你判断✨\n\n#KET #PET #剑桥英语 #英语备考 #初中英语 #英语学习',4,NULL,0,0,'2026-03-07 09:05:54','2026-03-07 10:36:44',1,NULL),(14,NULL,'报KET还是PET？3月开学后这张表帮你想清楚【样式示例v2】','Cathy','报KET还是PET？关键3个指标5分钟做决定。','<section style=\"max-width:680px;margin:0 auto;font-family:-apple-system,BlinkMacSystemFont,\'Helvetica Neue\',Arial,sans-serif\">\n\n<p style=\"color:#999;font-size:13px;margin:0 0 16px\">Original &nbsp;·&nbsp; Cathy &nbsp;·&nbsp; 英语陪跑 go</p>\n<hr style=\"border:none;border-top:1px solid #f0f0f0;margin:0 0 24px\">\n\n<p style=\"font-size:16px;line-height:1.9;color:#333;margin:0 0 20px\">\n报KET还是PET？这是每年开学家长问我最多的一个问题。<br>\n答案不难，<strong style=\"color:#e74c3c\">关键在于3个指标</strong>，对照一下，5分钟就能决定。\n</p>\n\n<section style=\"background:linear-gradient(135deg,#e8f4fd 0%,#d6eaf8 100%);border-left:4px solid #3498db;border-radius:0 12px 12px 0;padding:18px 20px;margin:0 0 16px\">\n  <p style=\"margin:0 0 8px;font-size:14px;font-weight:700;color:#2471a3;letter-spacing:1px\">? KET（A2级）适合这类孩子</p>\n  <p style=\"margin:0 0 6px;font-size:14px;color:#333;line-height:1.8\">✅ 小学5年级～初一 &nbsp;|&nbsp; 词汇量 600-1200个</p>\n  <p style=\"margin:0 0 6px;font-size:14px;color:#333;line-height:1.8\">✅ 能看懂英文菜单、简单告示</p>\n  <p style=\"margin:0;font-size:14px;color:#333;line-height:1.8\">✅ 校内英语成绩良好，想要证书背书</p>\n</section>\n\n<section style=\"background:linear-gradient(135deg,#fef9e7 0%,#fdebd0 100%);border-left:4px solid #f39c12;border-radius:0 12px 12px 0;padding:18px 20px;margin:0 0 24px\">\n  <p style=\"margin:0 0 8px;font-size:14px;font-weight:700;color:#d68910;letter-spacing:1px\">? PET（B1级）适合这类孩子</p>\n  <p style=\"margin:0 0 6px;font-size:14px;color:#333;line-height:1.8\">✅ 初一～初三 &nbsp;|&nbsp; 词汇量 1500-2500个</p>\n  <p style=\"margin:0 0 6px;font-size:14px;color:#333;line-height:1.8\">✅ 能读英文故事书、看原版动画不费力</p>\n  <p style=\"margin:0;font-size:14px;color:#333;line-height:1.8\">✅ 有冲击高中强基/竞赛英语的打算</p>\n</section>\n\n<h2 style=\"font-size:19px;font-weight:700;color:#2c3e50;border-left:4px solid #3498db;padding-left:12px;margin:0 0 16px;line-height:1.4\">\n  3分钟决定法：用这张表对照\n</h2>\n\n<section style=\"overflow-x:auto;margin:0 0 24px\">\n<table style=\"width:100%;border-collapse:collapse;font-size:14px\">\n  <thead>\n    <tr style=\"background:#3498db;color:#fff\">\n      <th style=\"padding:10px 14px;text-align:left;font-weight:600\">对比项</th>\n      <th style=\"padding:10px 14px;text-align:center;font-weight:600\">KET</th>\n      <th style=\"padding:10px 14px;text-align:center;font-weight:600\">PET</th>\n    </tr>\n  </thead>\n  <tbody>\n    <tr style=\"background:#fff\">\n      <td style=\"padding:10px 14px;border-bottom:1px solid #eee;color:#555\">适合年级</td>\n      <td style=\"padding:10px 14px;border-bottom:1px solid #eee;text-align:center\">小5～初一</td>\n      <td style=\"padding:10px 14px;border-bottom:1px solid #eee;text-align:center\">初一～初三</td>\n    </tr>\n    <tr style=\"background:#f9fbfe\">\n      <td style=\"padding:10px 14px;border-bottom:1px solid #eee;color:#555\">词汇量</td>\n      <td style=\"padding:10px 14px;border-bottom:1px solid #eee;text-align:center\">600-1200</td>\n      <td style=\"padding:10px 14px;border-bottom:1px solid #eee;text-align:center\">1500-2500</td>\n    </tr>\n    <tr style=\"background:#fff\">\n      <td style=\"padding:10px 14px;border-bottom:1px solid #eee;color:#555\">备考周期</td>\n      <td style=\"padding:10px 14px;border-bottom:1px solid #eee;text-align:center\">3-4个月</td>\n      <td style=\"padding:10px 14px;border-bottom:1px solid #eee;text-align:center\">4-6个月</td>\n    </tr>\n    <tr style=\"background:#f9fbfe\">\n      <td style=\"padding:10px 14px;color:#555\">含金量</td>\n      <td style=\"padding:10px 14px;text-align:center\">⭐⭐⭐</td>\n      <td style=\"padding:10px 14px;text-align:center\">⭐⭐⭐⭐⭐</td>\n    </tr>\n  </tbody>\n</table>\n</section>\n\n<h2 style=\"font-size:19px;font-weig